const TERM_INFO = [
  // M D
  [0, 2, 10, 23, 8, 23, 8, 23, 6, 21, 6, 21, 5, 20, 4, 19, 5, 20, 5, 21, 6, 21, 7, 22, 7, 23, 8, 23, 8, 23, 7, 22, 7, 22],
  [1, 3, 11, 24, 9, 24, 9, 24, 7, 22, 7, 22, 6, 21, 5, 20, 5, 21, 6, 22, 7, 23, 8, 24, 8, 24, 8, 23, 7, 23, 7, 23],
  [2, 3, 12, 25, 10, 25, 10, 25, 8, 23, 8, 23, 7, 22, 6, 21, 6, 22, 7, 22, 8, 23, 9, 24, 9, 24, 8, 24, 8, 23, 8, 23],
  [3, 4, 12, 26, 11, 26, 11, 26, 9, 24, 9, 24, 8, 23, 7, 22, 7, 22, 8, 23, 8, 24, 9, 25, 9, 25, 9, 24, 8, 24, 8, 24],
  [4, 4, 13, 27, 12, 27, 12, 27, 10, 25, 10, 25, 9, 24, 8, 23, 8, 23, 8, 24, 9, 24, 10, 25, 10, 25, 9, 25, 9, 24, 9, 24],
  [5, 5, 14, 28, 13, 28, 13, 28, 11, 26, 11, 26, 10, 25, 9, 24, 9, 24, 9, 25, 9, 25, 10, 26, 10, 26, 10, 25, 9, 25, 9, 25]
];

function getTerm(y, m, d) {
  let termName = null;
  const day = TERM_INFO[y % 6][2 * (m - 1) + (d >= TERM_INFO[y % 6][2 * (m - 1) + 1] ? 1 : 0)];
  if (d === day) {
    termName = SOLAR_TERMS[2 * (m - 1) + (d >= TERM_INFO[y % 6][2 * (m - 1) + 1] ? 1 : 0)].name;
  }
  return termName;
}

function getSolarTerm(date) {
  const y = date.getFullYear();
  const m = date.getMonth() + 1;
  const d = date.getDate();

  let term = getTerm(y, m, d);
  if (term) {
    const termIndex = SOLAR_TERMS.findIndex(t => t.name === term);
    return {
      ...SOLAR_TERMS[termIndex],
      date: `${String(m).padStart(2, '0')}.${String(d).padStart(2, '0')}`
    };
  }

  let tempDate = new Date(date.getTime());
  for (let i = 0; i < 45; i++) {
    tempDate.setDate(tempDate.getDate() - 1);
    const ty = tempDate.getFullYear();
    const tm = tempDate.getMonth() + 1;
    const td = tempDate.getDate();
    term = getTerm(ty, tm, td);
    if (term) {
      const termIndex = SOLAR_TERMS.findIndex(t => t.name === term);
      return {
        ...SOLAR_TERMS[termIndex],
        date: `${String(tm).padStart(2, '0')}.${String(td).padStart(2, '0')}`
      };
    }
  }
  return null;
}

export default { getSolarTerm };
